module top_module(

              q_out,

              en, i, rstn
              );parameter LATCH_BITS = 8;
   parameter RESET_VALUE = {LATCH_BITS{1'b0}};

   localparam LATCH_MSB= LATCH_BITS-1;

   input en;
   input [LATCH_MSB:0] i;
   input rstn;
   output [LATCH_MSB:0] q_out;
   reg    [LATCH_MSB:0] q_out;

   always @* begin
      if(rstn == 1'b0)
        q_out <= RESET_VALUE;
      else
        if(en)
          q_out <= i;

   end
endmodule
